import { AnalyticsService } from '../services/analytics.service.js';
import type {
  AnalyticsQuery,
  AnalyticsResponse,
  DashboardData,
  MetricDetail,
  MetricType,
  TimeGranularity,
  TimeRange,
  TopProduct,
} from '../models/analytics.js';

// ---------------------------------------------------------------------------
// Route-handler types
// ---------------------------------------------------------------------------

/**
 * Framework-agnostic request representation.
 *
 * Handlers receive this instead of an Express/Koa/Hono-specific request so
 * the analytics routes can be wired into any HTTP framework via a thin adapter.
 */
export interface RouteRequest {
  params: Record<string, string>;
  query: Record<string, string>;
}

/** Framework-agnostic response representation. */
export interface RouteResponse<T> {
  status: number;
  body: T;
}

/** Error response body returned when a request fails. */
export interface ErrorBody {
  success: false;
  error: string;
}

// ---------------------------------------------------------------------------
// Validation helpers
// ---------------------------------------------------------------------------

const VALID_TIME_RANGES: TimeRange[] = ['24h', '7d', '30d', '90d', 'custom'];
const VALID_METRIC_TYPES: MetricType[] = ['orders', 'revenue', 'users', 'products'];
const VALID_GRANULARITIES: TimeGranularity[] = ['hour', 'day', 'week', 'month'];

/** Parse and validate common analytics query parameters. */
function parseAnalyticsQuery(raw: Record<string, string>): AnalyticsQuery {
  const timeRange = (raw['timeRange'] ?? '30d') as TimeRange;
  if (!VALID_TIME_RANGES.includes(timeRange)) {
    throw new ValidationError(`Invalid timeRange "${timeRange}". Must be one of: ${VALID_TIME_RANGES.join(', ')}`);
  }

  if (timeRange === 'custom' && (!raw['startDate'] || !raw['endDate'])) {
    throw new ValidationError('startDate and endDate query params are required when timeRange is "custom"');
  }

  if (timeRange === 'custom') {
    const start = new Date(raw['startDate']!);
    const end = new Date(raw['endDate']!);
    if (isNaN(start.getTime())) {
      throw new ValidationError(`Invalid startDate "${raw['startDate']}". Must be a valid ISO-8601 date string`);
    }
    if (isNaN(end.getTime())) {
      throw new ValidationError(`Invalid endDate "${raw['endDate']}". Must be a valid ISO-8601 date string`);
    }
    if (start >= end) {
      throw new ValidationError('startDate must be before endDate');
    }
  }

  if (raw['granularity'] && !VALID_GRANULARITIES.includes(raw['granularity'] as TimeGranularity)) {
    throw new ValidationError(
      `Invalid granularity "${raw['granularity']}". Must be one of: ${VALID_GRANULARITIES.join(', ')}`,
    );
  }

  return {
    timeRange,
    startDate: raw['startDate'],
    endDate: raw['endDate'],
    granularity: raw['granularity'] as AnalyticsQuery['granularity'],
  };
}

/** Typed validation error so callers can distinguish bad input from server errors. */
export class ValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'ValidationError';
  }
}

