import { describe, it, expect, beforeEach, vi } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import { createAnalyticsHandlers, ValidationError } from '../../src/routes/analytics.routes.js';
import type { RouteRequest } from '../../src/routes/analytics.routes.js';

describe('Analytics Route Handlers', () => {
  let handlers: ReturnType<typeof createAnalyticsHandlers>;
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
    handlers = createAnalyticsHandlers(service);
  });

  describe('getDashboard', () => {
    it('should return 200 with dashboard data', async () => {
      const res = await handlers.getDashboard({
        params: {},
        query: { timeRange: '30d' },
      });

      expect(res.status).toBe(200);
      expect(res.body.success).toBe(true);
      expect('data' in res.body && res.body.data.summaries).toHaveLength(4);
      expect('query' in res.body && res.body.query.timeRange).toBe('30d');
    });

    it('should default timeRange to 30d when omitted', async () => {
      const res = await handlers.getDashboard({
        params: {},
        query: {},
      });

      expect('query' in res.body && res.body.query.timeRange).toBe('30d');
    });

    it('should include revenueTimeSeries and orderTimeSeries', async () => {
      const res = await handlers.getDashboard({
        params: {},
        query: { timeRange: '7d' },
      });

      expect(res.status).toBe(200);
      if ('data' in res.body) {
        expect(res.body.data.revenueTimeSeries).toBeDefined();
        expect(res.body.data.revenueTimeSeries.metric).toBe('revenue');
        expect(res.body.data.orderTimeSeries).toBeDefined();
        expect(res.body.data.orderTimeSeries.metric).toBe('order_count');
        expect(res.body.data.topProducts).toBeDefined();
        expect(res.body.data.generatedAt).toBeDefined();
      }
    });

    it('should respect granularity parameter', async () => {
      const res = await handlers.getDashboard({
        params: {},
        query: { timeRange: '7d', granularity: 'day' },
      });

      expect(res.status).toBe(200);
      if ('data' in res.body) {
        expect(res.body.data.revenueTimeSeries.points.length).toBeGreaterThan(0);
      }
    });

    it('should return 500 when service throws', async () => {
      vi.spyOn(service, 'getDashboard').mockRejectedValueOnce(new Error('DB failure'));

      const res = await handlers.getDashboard({
        params: {},
        query: { timeRange: '30d' },
      });

      expect(res.status).toBe(500);
      expect(res.body.success).toBe(false);
      if ('error' in res.body) {
        expect(res.body.error).toBe('DB failure');
      }
    });
  });

  describe('getMetricDetail', () => {
    it('should return 200 for valid metric type', async () => {
      const res = await handlers.getMetricDetail({
        params: { type: 'revenue' },
        query: { timeRange: '7d' },
      });

      expect(res.status).toBe(200);
      if ('data' in res.body) {
        expect(res.body.data.summary.metric).toBe('revenue');
      }
    });

    it('should throw ValidationError for invalid metric type', async () => {
      await expect(
        handlers.getMetricDetail({
          params: { type: 'invalid' },
          query: { timeRange: '7d' },
        }),
      ).rejects.toThrow(ValidationError);
    });

    it('should return metric detail with timeSeries and generatedAt', async () => {
      const res = await handlers.getMetricDetail({
        params: { type: 'orders' },
        query: { timeRange: '24h' },
      });

      expect(res.status).toBe(200);
      if ('data' in res.body) {
        expect(res.body.data.summary).toBeDefined();
        expect(res.body.data.timeSeries).toBeDefined();
        expect(res.body.data.generatedAt).toBeDefined();
        expect(res.body.data.summary.metric).toBe('orders');
        expect(res.body.data.summary.label).toBe('Total Orders');
        expect(res.body.data.timeSeries.points).toBeInstanceOf(Array);
      }
    });

    it('should work for all valid metric types', async () => {
      const types = ['orders', 'revenue', 'users', 'products'] as const;
      for (const type of types) {
        const res = await handlers.getMetricDetail({
          params: { type },
          query: { timeRange: '30d' },
        });
        expect(res.status).toBe(200);
        if ('data' in res.body) {
          expect(res.body.data.summary.metric).toBe(type);
        }
      }
    });

    it('should return 500 when service throws', async () => {
      vi.spyOn(service, 'getMetricDetail').mockRejectedValueOnce(new Error('Compute error'));

      const res = await handlers.getMetricDetail({
        params: { type: 'revenue' },
        query: { timeRange: '7d' },
      });

      expect(res.status).toBe(500);
      expect(res.body.success).toBe(false);
      if ('error' in res.body) {
        expect(res.body.error).toBe('Compute error');
      }
    });
  });

  describe('getTopProducts', () => {
    it('should return 200 with top products', async () => {
      const res = await handlers.getTopProducts({
        params: {},
        query: { timeRange: '30d', limit: '5' },
      });

      expect(res.status).toBe(200);
      expect(res.body.success).toBe(true);
    });

    it('should throw ValidationError for invalid timeRange', async () => {
      await expect(
        handlers.getTopProducts({
          params: {},
          query: { timeRange: 'invalid' },
        }),
      ).rejects.toThrow(ValidationError);
    });

    it('should default limit to 10', async () => {
      const res = await handlers.getTopProducts({
        params: {},
        query: { timeRange: '30d' },
      });

      expect(res.status).toBe(200);
    });

    it('should clamp limit to range [1, 100]', async () => {
      // limit=0 should clamp to 10 (default, since parseInt('0') || 10 = 10... actually 0||10=10)
      const res1 = await handlers.getTopProducts({
        params: {},
        query: { timeRange: '30d', limit: '-5' },
      });
      expect(res1.status).toBe(200);

      const res2 = await handlers.getTopProducts({
        params: {},
        query: { timeRange: '30d', limit: '999' },
      });
      expect(res2.status).toBe(200);
    });

    it('should handle non-numeric limit gracefully', async () => {
      const res = await handlers.getTopProducts({
        params: {},
        query: { timeRange: '30d', limit: 'abc' },
      });

      expect(res.status).toBe(200);
      expect(res.body.success).toBe(true);
    });

    it('should return 500 when service throws', async () => {
      vi.spyOn(service, 'getTopProducts').mockRejectedValueOnce(new Error('Query failed'));

      const res = await handlers.getTopProducts({
        params: {},
        query: { timeRange: '30d' },
      });

      expect(res.status).toBe(500);
      expect(res.body.success).toBe(false);
      if ('error' in res.body) {
        expect(res.body.error).toBe('Query failed');
      }
    });
  });

  describe('input validation', () => {
    it('should throw ValidationError for invalid granularity', async () => {
      await expect(
        handlers.getDashboard({
          params: {},
          query: { timeRange: '30d', granularity: 'invalid' },
        }),
      ).rejects.toThrow(ValidationError);
    });

    it('should accept all valid granularities', async () => {
      for (const granularity of ['hour', 'day', 'week', 'month']) {
        const res = await handlers.getDashboard({
          params: {},
          query: { timeRange: '7d', granularity },
        });
        expect(res.status).toBe(200);
      }
    });

    it('should throw ValidationError for invalid custom startDate', async () => {
      await expect(
        handlers.getDashboard({
          params: {},
          query: { timeRange: 'custom', startDate: 'not-a-date', endDate: '2025-01-31' },
        }),
      ).rejects.toThrow(ValidationError);
    });

    it('should throw ValidationError for invalid custom endDate', async () => {
      await expect(
        handlers.getDashboard({
          params: {},
          query: { timeRange: 'custom', startDate: '2025-01-01', endDate: 'bad' },
        }),
      ).rejects.toThrow(ValidationError);
    });

    it('should throw ValidationError when startDate >= endDate', async () => {
      await expect(
        handlers.getDashboard({
          params: {},
          query: { timeRange: 'custom', startDate: '2025-02-01', endDate: '2025-01-01' },
        }),
      ).rejects.toThrow(ValidationError);

      await expect(
        handlers.getDashboard({
          params: {},
          query: { timeRange: 'custom', startDate: '2025-01-15', endDate: '2025-01-15' },
        }),
      ).rejects.toThrow(ValidationError);
    });

    it('should accept valid custom date range', async () => {
      const res = await handlers.getDashboard({
        params: {},
        query: { timeRange: 'custom', startDate: '2025-01-01', endDate: '2025-01-31' },
      });
      expect(res.status).toBe(200);
    });

    it('should throw ValidationError for missing custom dates', async () => {
      await expect(
        handlers.getDashboard({
          params: {},
          query: { timeRange: 'custom' },
        }),
      ).rejects.toThrow(ValidationError);
    });
  });
});
